class Solution(object):
    def discountPrices(self, sentence, discount):
        words = sentence.split()
        result = []
        for word in words:
            if word[0] == '$' and word[1:].isdigit():
                price = int(word[1:])
                discounted = price * (1 - discount / 100.0)
                result.append(f"${discounted:.2f}")
            else:
                result.append(word)
        return ' '.join(result)
